module dynamic_range_compressor(  
    input signed [4:0] obf_audio_in,  
    input signed [4:0] threshold,  
    output reg signed [4:0] audio_out  
);  
    always @(*) begin  
        if (obf_audio_in > threshold)  
            audio_out = threshold;  
        else  
            audio_out = obf_audio_in;  
    end  
endmodule
